3	import {
4	  flush,
5	  SEMANTIC_ATTRIBUTE_SENTRY_ORIGIN,
6	  SEMANTIC_ATTRIBUTE_SENTRY_SOURCE,
7	  startSpanManual,
8	  withActiveSpan,
9	  withIsolationScope,
10	} from "@sentry/core";
11	import { InngestMiddleware, NonRetriableError } from "@vendor/inngest";
12	
13	import type { JournalEntry } from "./context";
14	import { createStore, requestStore } from "./context";
15	import { log } from "./log/next";
16	
17	const MAX_JOURNAL_ENTRIES = 50;
18	
19	/**
20	 * Extracts common context fields from Inngest event data.
21	 * Filters out undefined values so ALS context stays clean.
22	 */
23	function extractEventContext(
24	  data: Record<string, unknown> | undefined
25	): Record<string, unknown> {
26	  if (!data) {
27	    return {};
28	  }
29	
30	  const fields: Record<string, unknown> = {
31	    correlationId: data.correlationId,
32	    provider: data.provider,
33	    clerkOrgId: data.clerkOrgId ?? data.orgId,
34	    installationId: data.installationId,
35	  };
36	
37	  return Object.fromEntries(
38	    Object.entries(fields).filter(([, v]) => v !== undefined)
39	  );
40	}
41	
42	/**
43	 * Creates the unified Inngest observability middleware.
44	 *
45	 * Consolidates three capabilities into a single middleware:
46	 * 1. ALS context seeding — auto-enriches all `log.*` calls
47	 * 2. Sentry integration — isolation scope, manual spans, selective error capture
48	 * 3. Step journal — records executed steps via beforeExecution/afterExecution hooks
49	 *
50	 * Replaces `@inngest/middleware-sentry`.
51	 *
52	 * Architecture notes:
53	 * - Uses `startSpanManual` (not `startSpan`) because the span must live across
54	 *   multiple lifecycle hooks. `startSpan` auto-ends when its callback returns,
55	 *   which would close the span immediately after hook registration (~0ms).
56	 *   `startSpanManual` requires explicit `.end()` in `beforeResponse`.
57	 *   (Matches the pattern in `@inngest/middleware-sentry`.)
58	 *
59	 * - Hooks access `store` via closure, NOT via ALS (`getJournal`/`pushJournal`).
60	 *   Inngest wraps hooks in `waterfall`/`cacheFn` which creates promise chains
61	 *   that break `AsyncLocalStorage` propagation. `getStore()` returns undefined
62	 *   inside hooks even after `enterWith`. Direct store access via closure is
63	 *   reliable regardless of async context boundaries.
64	 *
65	 * - ALS is seeded in `beforeMemoization` via `requestStore.enterWith()` for
66	 *   the benefit of USER function code — `log.*` calls inside Inngest functions
67	 *   automatically get context enrichment. The middleware hooks themselves don't
68	 *   depend on ALS.
69	 *
70	 * - Hooks run outside `withIsolationScope`'s async context, so we use
71	 *   `scope.captureException()` (via closure) instead of the global
72	 *   `captureException` to ensure errors are captured in the correct
73	 *   isolation scope. (Matches `@inngest/middleware-sentry`'s pattern.)
74	 */
75	export function createInngestObservabilityMiddleware() {
76	  return new InngestMiddleware({
77	    name: "lightfast:observability",
78	
79	    init() {
80	      return {
81	        onFunctionRun({ ctx, fn }) {
82	          const fnId = fn.id();
83	          const eventData = (ctx.event?.data as Record<string, unknown>) ?? {};
84	          const eventContext = extractEventContext(eventData);
85	
86	          // Generate correlationId from runId for cron functions with no event data
87	          const correlationId =
88	            (eventContext.correlationId as string | undefined) ?? ctx.runId;
89	
90	          const alsContext = {
91	            requestId: ctx.runId,
92	            inngestFunctionId: fnId,
93	            inngestEventName: ctx.event?.name,
94	            ...eventContext,
95	            correlationId,
96	          };
97	
98	          const startTime = Date.now();
99	          let execStartTime: number | undefined;
100	
101	          // Create store eagerly; ALS is seeded in beforeMemoization for user code.
102	          // Hooks access store via closure (see architecture note above).
103	          const store = createStore(
104	            alsContext as { requestId: string } & Record<string, unknown>
105	          );
106	
107	          /** Push a journal entry directly to the store (bypasses ALS). */
108	          function journal(
109	            level: JournalEntry["level"],
110	            msg: string,
111	            meta?: Record<string, unknown>
112	          ) {
113	            if (store.journal.length < MAX_JOURNAL_ENTRIES) {
114	              store.journal.push({ ts: Date.now(), level, msg, meta });
115	            }
116	          }
117	
118	          journal("info", "function:start");
119	
120	          // Wrap in Sentry isolation scope (synchronous — matches sentryMiddleware)
121	          return withIsolationScope((scope) => {
122	            scope.setTag("inngest.function.id", fnId);
123	            scope.setTag("inngest.run.id", ctx.runId);
124	            if (ctx.event?.name) {
125	              scope.setTag("inngest.event.name", ctx.event.name);
126	            }
127	
128	            // startSpanManual: span lives until explicit .end() in beforeResponse
129	            return startSpanManual(
130	              {
131	                name: `inngest/${fnId}`,
132	                op: "function.inngest",
133	                attributes: {
134	                  [SEMANTIC_ATTRIBUTE_SENTRY_SOURCE]: "route",
135	                  [SEMANTIC_ATTRIBUTE_SENTRY_ORIGIN]:
136	                    "auto.function.inngest.middleware",
137	                  "inngest.run.id": ctx.runId,
138	                  "inngest.event.name": ctx.event?.name ?? "unknown",
139	                },
140	                scope,
141	              },
142	              (reqSpan) => {
143	                // Add Sentry trace ID to store for log correlation
144	                const traceId = reqSpan.spanContext().traceId;
145	                if (traceId) {
146	                  store.ctx = { ...store.ctx, traceId };
147	                }
148	
149	                return {
150	                  // Seed ALS for user function code. enterWith may not propagate
151	                  // to hooks (due to waterfall/cacheFn promise chains) but it
152	                  // DOES propagate to the user function executed via runAsPromise.
153	                  beforeMemoization() {
154	                    requestStore.enterWith(store);
155	                  },
156	
157	                  beforeExecution() {
158	                    execStartTime = Date.now();
159	                    journal("info", "execution:start");
160	                  },
161	
162	                  afterExecution() {
163	                    const execMs = execStartTime
164	                      ? Date.now() - execStartTime
165	                      : undefined;
166	                    journal("info", "execution:done", {
167	                      ...(execMs !== undefined && { durationMs: execMs }),
168	                    });
169	                  },
170	
171	                  transformOutput({ result, step: stepInfo }) {
172	                    const durationMs = Date.now() - startTime;
173	                    const err = result.error;
174	
175	                    if (err) {
176	                      const isBusinessError = err instanceof NonRetriableError;
177	                      const errorMessage =
178	                        err instanceof Error ? err.message : String(err);
179	
