3	import { ORPCError } from "@orpc/client";
4	import {
5	  captureException,
6	  getActiveSpan,
7	  SEMANTIC_ATTRIBUTE_SENTRY_ORIGIN,
8	  SEMANTIC_ATTRIBUTE_SENTRY_SOURCE,
9	  startSpan,
10	  withIsolationScope,
11	} from "@sentry/core";
12	
13	import { log } from "./log/next";
14	import { withRequestContext } from "./request";
15	
16	/**
17	 * Create an oRPC observability middleware that consolidates:
18	 * - Sentry isolation scope + span creation
19	 * - Error classification via ORPCError.status
20	 * - Selective Sentry capture (server errors only)
21	 * - Structured logging with trace ID correlation
22	 * - ALS request context seeding (requestId + traceId)
23	 * - Request journal emission
24	 *
25	 * Follows the same pattern as createObservabilityMiddleware in trpc.ts.
26	 *
27	 * Key differences from tRPC middleware:
28	 * - oRPC errors propagate as thrown exceptions (not result.ok/error)
29	 * - ORPCError has .status directly (no getHTTPStatusCodeFromError needed)
30	 * - path is readonly string[] (joined with "." for span names)
31	 * - Auth fields are enriched by downstream auth middleware via enrichContext(),
32	 *   then read back from the enriched ctx returned by withRequestContext
33	 */
34	export function createORPCObservabilityMiddleware() {
35	  return async ({
36	    context,
37	    next,
38	    path,
39	  }: {
40	    context: { requestId: string };
41	    next: (...args: any[]) => Promise<any>;
42	    path: readonly string[];
43	  }) => {
44	    const procedurePath = path.join(".");
45	    const { requestId } = context;
46	
47	    return withIsolationScope(async (scope) => {
48	      scope.setContext("orpc", { procedure_path: procedurePath });
49	
50	      return startSpan(
51	        {
52	          name: `orpc/${procedurePath}`,
53	          op: "rpc.server",
54	          attributes: {
55	            [SEMANTIC_ATTRIBUTE_SENTRY_SOURCE]: "route",
56	            [SEMANTIC_ATTRIBUTE_SENTRY_ORIGIN]: "auto.rpc.orpc",
57	          },
58	        },
59	        async () => {
60	          const span = getActiveSpan();
61	          const traceId = span?.spanContext().traceId;
62	
63	          // Catch errors inside withRequestContext so we still get journal + durationMs.
64	          // oRPC errors propagate as thrown exceptions (unlike tRPC's result.ok pattern).
65	          const {
66	            result,
67	            journal,
68	            durationMs,
69	            ctx: enrichedCtx,
70	          } = await withRequestContext(
71	            { requestId, ...(traceId && { traceId }) },
72	            async () => {
73	              try {
74	                const value = await next();
75	                return { ok: true as const, value };
76	              } catch (error) {
77	                return { ok: false as const, error };
78	              }
79	            }
80	          );
81	
82	          // Spread enriched context — includes base fields (requestId, traceId)
83	          // plus auth fields added by downstream enrichContext() (userId, clerkOrgId, authType)
84	          const meta = {
85	            path: procedurePath,
86	            durationMs,
87	            ...enrichedCtx,
88	          };
89	
90	          if (result.ok) {
91	            log.info("[orpc] ok", { ...meta, ok: true });
92	            if (journal.length > 0) {
93	              log.info("[orpc] request journal", {
94	                path: procedurePath,
95	                durationMs,
96	                ok: true,
97	                entryCount: journal.length,
98	                entries: journal,
99	              });
100	            }
101	            return result.value;
102	          }
103	
104	          // -- Error classification (mirrors trpc.ts:116-141) --
105	          const error = result.error;
106	          const isKnown = error instanceof ORPCError;
107	          const httpStatus = isKnown ? error.status : 500;
108	          const errorCode = isKnown ? error.code : "INTERNAL_SERVER_ERROR";
109	
110	          if (httpStatus >= 500) {
111	            log.error("[orpc] server error", { ...meta, ok: false, errorCode });
112	
113	            scope.setTag("orpc.path", procedurePath);
114	            scope.setTag("orpc.error_code", errorCode);
115	            scope.setExtra("durationMs", durationMs);
116	            scope.setExtra("requestId", requestId);
117	
118	            // Unwrap .cause for better Sentry grouping (same as trpc.ts:127-131)
119	            const reportedError =
120	              errorCode === "INTERNAL_SERVER_ERROR" &&
121	              error instanceof Error &&
122	              error.cause instanceof Error
123	                ? error.cause
124	                : error;
125	
126	            captureException(reportedError, {
127	              mechanism: {
128	                handled: false,
129	                type: "auto.rpc.orpc.middleware",
130	              },
131	            });
132	          } else {
133	            log.info("[orpc] client error", {
134	              ...meta,
135	              ok: false,
136	              errorCode,
137	            });
138	          }
139	
140	          if (journal.length > 0) {
141	            log.info("[orpc] request journal", {
142	              path: procedurePath,
143	              durationMs,
144	              ok: false,
145	              entryCount: journal.length,
146	              entries: journal,
147	            });
148	          }
149	
150	          // Re-throw so oRPC's handler serializes the error response
151	          throw error;
152	        }
153	      );
154	    });
155	  };
156	}
