            log.info("[orpc] request journal", {
              path: procedurePath,
              durationMs,
              ok: false,
              entryCount: journal.length,
              entries: journal,
            });
          }

          // Re-throw so oRPC's handler serializes the error response
          throw error;
        }
      );
    });
  };
}

